        // const userSelectedAnswers = {};
        // userSolvedQuestions.forEach(({ questionId, selectedAnswer }) => {
        //   userSelectedAnswers[questionId] = selectedAnswer;
        // });

        // setSelectedAnswers(userSelectedAnswers);




